        console.log\("  revealedLane: " + JSON.stringify\(data.revealedLane\)\);
        console.log\("  revealedLane.hasCar: " + data.revealedLane.hasCar\);
      } else {
        console.log\("  revealedLane: " + data.revealedLane\);
