        if \(knownFields.indexOf\(key\) === -1\) {
          console.log\("  [EXTRA FIELD] " + key + ": " + JSON.stringify\(data[key]\)\);
        }
      }\);

      crossedEvents.push\(Object.assign\({}, data, { requestedLane: currentLane }\)\);

      if \(data.safe\) {
        currentLane++;
        setTimeout\(function\(\) {
          console.log\("[GAME " + gameNumber + "] Sending game:cross for lane " + currentLane + "..."\);
