          console.log\("    Lane " + idx + ": hasCar=" + lane.hasCar + ", " + JSON.stringify\(lane\)\);
        }\);
      } else {
        console.log\("  revealedLanes: " + data.revealedLanes\);
      }
      var knownFields2 = ["result", "multiplier", "profit", "revealedLanes"];
