        var bugFound = false;
        crossedEvents.forEach\(function\(crossEvt, idx\) {
          var crossedLaneIdx = crossEvt.lane !== undefined ? crossEvt.lane : idx;
          var revealedByIdx = data.revealedLanes[crossedLaneIdx];
          var revealedByIdxMinus1 = data.revealedLanes[crossedLaneIdx - 1];

          console.log\("  Crossed event #" + \(idx + 1\) + ": lane=" + crossEvt.lane + ", safe=" + crossEvt.safe + ", isSafeZone=" + crossEvt.isSafeZone\);

          if \(revealedByIdx\) {
            console.log\("    -> revealedLanes[" + crossedLaneIdx + "].hasCar = " + revealedByIdx.hasCar\);
