      socket.removeAllListeners\("game:crossed"\);
      socket.removeAllListeners\("game:over"\);
      socket.removeAllListeners\("game:error"\);
      resolve\({ crossedEvents: crossedEvents, gameOverData: gameOverData }\);
    }\);

    console.log\("[GAME " + gameNumber + "] Emitting game:start with amount=5, difficulty=1"\);
    socket.emit\("game:start", { amount: 5, difficulty: 1 }\);
  }\);
}

async function main\(\) {
  console.log\("Connecting to Socket.io at " + SERVER\);

  var socket = io\(SERVER, {
    auth: { token: TOKEN },
    transports: ["websocket"],
  }\);

  await new Promise\(function\(resolve, reject\) {
    socket.on\("connect", function\(\) {
      console.log\("Connected! Socket ID: " + socket.id\);
      resolve\(\);
    }\);
    socket.on\("connect_error", function\(err\) {
      console.error\("Connection error: " + err.message\);
      reject\(err\);
    }\);
  }\);

  socket.on\("balance:update", function\(data\) {
    console.log\("[BALANCE UPDATE] " + JSON.stringify\(data\)\);
  }\);

  var allResults = [];

  for \(var i = 1; i <= 3; i++\) {
    try {
      var result = await runGame\(socket, i\);
      allResults.push\(result\);
    } catch \(err\) {
      console.error\("Game " + i + " failed: " + err\);
    }
    await sleep\(1000\);
  }

  console.log\("\\n" + "=".repeat\(60\)\);
  console.log\("FINAL SUMMARY ACROSS ALL GAMES"\);
  console.log\("=".repeat\(60\)\);
  allResults.forEach\(function\(r, idx\) {
    var gNum = idx + 1;
    var ce = r.crossedEvents;
    var go = r.gameOverData;
    console.log\("Game " + gNum + ": " + ce.length + " lanes crossed, result=" + go.result + ", multiplier=" + go.multiplier + ", profit=" + go.profit\);

    if \(go.revealedLanes\) {
      ce.forEach\(function\(crossEvt\) {
        var laneIdx = crossEvt.lane;
        for \(var offset = -1; offset <= 1; offset++\) {
          var checkIdx = laneIdx + offset;
          if \(checkIdx >= 0 && checkIdx < go.revealedLanes.length\) {
            var rl = go.revealedLanes[checkIdx];
            if \(crossEvt.safe === true && rl.hasCar === true\) {
              console.log\("  *** CONFIRMED BUG in Game " + gNum + ": crossed lane " + laneIdx + " \(safe=true\) but revealedLanes[" + checkIdx + "].hasCar=true ***"\);
            }
          }
        }
      }\);
    }
  }\);

  console.log\("\\nDone. Disconnecting."\);
  socket.disconnect\(\);
  process.exit\(0\);
}

main\(\).catch\(function\(err\) {
  console.error\("Fatal error: " + err\);
  process.exit\(1\);
}\);
